import numpy as np
import numpy.typing as npt
from time import time
from rory.core.utils.utils import Utils
from rory.core.security.cryptosystem.FDHOpe import Fdhope
from rory.core.interfaces.client_result import ClientResult
from rory.core.logger.Dumblogger import DumbLogger
from rory.core.security.cryptosystem.liu import Liu
from mictlanx.utils.segmentation import Chunks
from typing import List,Generator,Tuple,Awaitable
from concurrent.futures import ProcessPoolExecutor,as_completed
from typing import Tuple,Dict,Generator,List
import numpy.typing as npt
from rory.core.interfaces.cipherscheme_result import CipherschemeResult  #Import only for the type

"""
Description:
	A class that represents the preparation step, performed by data owners, 
	to securely externalize their data to the TPDM that provides DMaaS.
Attributes:
	m: int   - constraints [ m >= 3 ]
		Number of attributes of SK
	liu_scheme: Liu <object>
		represent a symmetric encryption scheme
	fdh_ope: 
		represents the Frequency and Distribution Hiding OPE (FDH-OPE) 
		scheme to facilitate operations for UDM.
"""
class DataOwner(object):

	def __init__(self, m:int, liu_scheme:Liu, sens:float=0.01):
		self.sens = sens
		self.m              = m 
		self.liu_scheme:Liu = liu_scheme
		self.sk             = self.liu_scheme.secretKey( m = self.m )
		self.messageIntervals:Dict[str,Tuple[float,float]] = {} 
		self.cypherIntervals:Dict[str,Tuple[float,float]]  = {}
		self.encrypted_threshold = 0
		

	"""
	Description:
		obtains the chunks, starts a process pool and sends each process 
		with its respective chunk to perform the corresponding process
	Parameters:
		plaintext_matrix: original dataset from which chunks will be extracted
		algorithm: algorithm selected by the user
		num_chunks: number of chunks in which the dataset will be split into
		group_id: id to which all chunks belong for the integration process
		max_workers: maximum number of processes to be initiated
	"""
	def processSegmentation(self, plaintext_matrix:npt.NDArray, algorithm:str, num_chunks:int, group_id:str, max_workers:int)-> Generator[Tuple[int,ClientResult],None,None]:
		chunks:Chunks = Chunks.from_ndarray(
			ndarray    = plaintext_matrix, 
			num_chunks = num_chunks, 
			group_id   = group_id
			).unwrap()
		futures:List[Awaitable[ClientResult]] = []
		indexes = []
		with ProcessPoolExecutor(max_workers = max_workers) as executor:
			try:
				for chunk in chunks.iter():
					fut = executor.submit(self.liu_encrypt_matrix_chunk, 
						   plaintext_matrix = chunk.to_ndarray().unwrap()
						)
					futures.append(fut)
					indexes.append(chunk.index)
				for i,future in enumerate(as_completed(futures,timeout=500)):
					x:ClientResult = future.result()
					yield (indexes[i],x)
			except Exception as e:
				raise e
	
	"""
	Description:
		Encrypt matrix with Liu's scheme
	Parameters:
		plaintext_matrix: 
	"""
	def liu_encrypt_matrix_chunk(self, plaintext_matrix:npt.NDArray) -> npt.NDArray :
		# Dshape = Utils.getShapeOfMatrix(plaintext_matrix)
		# a      = Dshape[1]

		encryption_result = self.liu_scheme.encryptMatrix( #The plaintext is sent to Liu scheme to encrypt
			plaintext_matrix = plaintext_matrix,
			secret_key       = self.sk,
			m                = self.m
		)

		return encryption_result.matrix


	"""
	description: Data preparation.
	attributes: 
		plaintext_matrix: original dataset (numerical)
		a: number of attributes of D
		threshold: how close the records must be to belong to the same cluster
		algorithm: clustering algorithm to use
	"""
	def outsourcedData(self, plaintext_matrix:npt.NDArray, threshold:float=0.01, algorithm:str= "SKMEANS") -> ClientResult:
		Dshape           = Utils.getShapeOfMatrix(plaintext_matrix)
		a                = Dshape[1]

		encryption_result = self.liu_scheme.encryptMatrix( #The plaintext is sent to Liu scheme to encrypt
			plaintext_matrix = plaintext_matrix,
			secret_key       = self.sk,
			m                = self.m
		)

		start_time_udm = time() 
		U = self.get_U( #U is generated according to the chosen algorithm
			algorithm         = algorithm,
			plaintext_matrix  = plaintext_matrix,
			threshold         = threshold,
		)
		encrypted_threshold = self.encrypt_threshold(
			threshold = threshold
			)
		udm_time = time() - start_time_udm

		return ClientResult(
			UDM                   = U,
			udm_time              = udm_time, 
			encrypted_matrix      = encryption_result.matrix,
			encrypted_matrix_time = encryption_result.time,
			messageIntervals      = self.messageIntervals,
			cypherIntervals       = self.cypherIntervals,
			encrypted_threshold   = encrypted_threshold
		)

	def outsourcedDataClassification(self, plaintext_matrix:npt.NDArray, algorithm:str= "SKNN"):
		
		encryption_result = self.liu_scheme.encryptMatrix( #The plaintext is sent to Liu scheme to encrypt
			plaintext_matrix = plaintext_matrix,
			secret_key       = self.sk,
			m                = self.m
		)
		#return encryption_result
		return ClientResult(
				encrypted_matrix      = encryption_result.matrix,
				encrypted_matrix_time = encryption_result.time
			)
	"""
	description: allows to generate the matrix U according to the type of algorithm to use
	attributes:
		plaintext_matrix: original dataset (numerical)
		threshold: how close the records must be to belong to the same cluster
		algorithm: clustering algorithm to use
	"""
	def get_U(self, plaintext_matrix:npt.NDArray, algorithm:str,**kwargs) -> npt.NDArray:
		logger = kwargs.get("logger",DumbLogger())
		logger.debug("GET_U_INIT")
		if (algorithm == "SKMEANS"): 
			U  = self.calculate_UDM( #Matrix UDM is created
				plaintext_matrix = plaintext_matrix
				)
		elif(algorithm == "DBSKMEANS"):
			U  = self.calculate_UDM( # Matrix UDM is created
				plaintext_matrix = plaintext_matrix
				)
			self.messageIntervals, self.cypherIntervals = Fdhope.keygen( #the intervals (SK) of each space are generated
				dataset = U
			)
		elif(algorithm == "DBSNNC"):
			U  = self.calculate_DM( #Matrix ED is created
				plaintext_matrix = plaintext_matrix
			)
			self.messageIntervals, self.cypherIntervals = Fdhope.keygen( #the intervals (SK) of each space are generated
				dataset = U
			)
		elif(algorithm == "NNC"):
			logger.debug("GET_U_NNC")
			U  = self.calculate_DM( #Matrix ED is created
				plaintext_matrix = plaintext_matrix
			)
		else:
			raise Exception("UKNOWN ALGORITHM: {}" .format(algorithm))
		logger.debug("GET_U_NNC {}".format(U.shape))
		return U


	def encrypt_udm_chunks(self,plaintext_matrix:npt.NDArray,threshold:float = 0.0,algorithm:str="DBSKMEANS") -> CipherschemeResult:
		encrypted_threshold:float = 0.0 #threshold is 0 if not required by the algorithm

		if (algorithm == "DBSKMEANS"): #if the algorithm is dbskmeans, one more dimension needs to be traversed
			U = Fdhope.encryptTensor( #the lower triangle of U is encrypted
				plaintext_tensor = plaintext_matrix, 
				sens             = self.sens, 
				messagespace     = self.messageIntervals, 
				cipherspace      = self.cypherIntervals
			)
		elif(algorithm == "DBSNNC"):
			U = Fdhope.encryptMatrix( #the lower triangle of U is encrypted
				plaintext_matrix = plaintext_matrix, 
				sens             = self.sens, 
				messagespace     = self.messageIntervals, 
				cipherspace      = self.cypherIntervals
			)
			self.encrypted_threshold = Fdhope.encrypt( #Threshold is encrypted
				plaintext    = threshold,
				messagespace = self.messageIntervals, 
				cipherspace  = self.cypherIntervals
			)
		else:
			raise Exception("UKNOWN ALGORITHM: {}" .format(algorithm))
		return U


	"""
	description: allows to encrypt the U
	attributes:
		U: matrix to be encrypted
		algorithm: clustering algorithm to use
	"""
	def encrypt_U(self, U:npt.NDArray, algorithm:str) -> npt.NDArray:
		Ushape    = Utils.getShapeOfMatrix(U)
		
		for x in range(Ushape[0]): 
			for y in range(x):
				if (algorithm == "DBSKMEANS"): #if the algorithm is dbskmeans, one more dimension needs to be traversed
					for z in range(Ushape[2]):
						U[x][y][z] = Fdhope.encrypt( #the lower triangle of U is encrypted
							plaintext    = U[x][y][z], 
							sens         = self.sens, 
							messagespace = self.messageIntervals, 
							cipherspace  = self.cypherIntervals
						)
						U[y][x][z] = U[x][y][z] #the equivalent position is obtained to fill the upper triangle
				elif(algorithm == "DBSNNC"):
					U[x][y] = Fdhope.encrypt( #the lower triangle of U is encrypted
						plaintext    = U[x][y], 
						messagespace = self.messageIntervals, 
						cipherspace  = self.cypherIntervals
					)
					U[y][x] = U[x][y] #the equivalent position is obtained to fill the upper triangle
		return np.array(U)

	"""
	description: UDM matrix calculation
	attributes:
		D: numeric dataset
		a: number of attributes of D
	"""
	def calculate_UDM(self, plaintext_matrix:npt.NDArray, mode:str="diff") -> npt.NDArray:
		try:
			num_rows        = Utils.getShapeOfMatrix(plaintext_matrix)
			expanded_matrix = np.expand_dims(plaintext_matrix, axis=1)  # Shape: (n, 1, a)
			
			if mode =="diff":
				result = expanded_matrix - plaintext_matrix  # Shape: (n, n, a)
			elif mode =="diff-abs":
				result = np.abs(expanded_matrix - plaintext_matrix)  # Shape: (n, n, a)
			else:
				result  = expanded_matrix - plaintext_matrix  # Shape: (n, n, a)
			return np.array(result)		
		except Exception as e:
			print(e)
			raise e

	"""
	description: EDM matrix calculation
	attributes:
		plaintext_matrix: numeric dataset
		a: number of attributes of D
	"""
	def calculate_DM(self, plaintext_matrix:npt.NDArray) -> npt.NDArray: #Calculo de la matriz DM
		DShape = Utils.getShapeOfMatrix(plaintext_matrix)
		a      = DShape[1]
		
		ED     = []
		for x in range(DShape[0]): 
			ED.append([])
		
		for x in range(DShape[0]): #Llenado de U con distancias entre los datos en plano	
			for y in range(DShape[0]):
				dist = 0
				for z in range(a):
					dist += abs(plaintext_matrix[x][z] - plaintext_matrix[y][z])
				ED[x].append(dist)
		return np.array(ED)
		
	

	def encrypt_threshold(self, threshold:int=0.01):
		encrypted_threshold = Fdhope.encrypt( #Threshold is encrypted
				plaintext    = threshold,
				messagespace = self.messageIntervals, 
				cipherspace  = self.cypherIntervals
			)
		return encrypted_threshold
	
	"""
	description: dataowner participation for shift matrix decryption
	attributes:
		S1: shift matrix
		m: number of attributes of SK
	"""
	def userActions(self,**kwargs):
		S1 = kwargs.get("shift_matrix",[])
		m  = kwargs.get("m",3)
		S  = self.liu_scheme.decryptMatrix(
			ciphertext_matrix = S1,
			secret_key        = self.sk,
			m                 = self.m
		)
		return S.matrix

	
	"""
	description: decrypt final clusters
	attributes:
		cipher_cluster: set of encrypted clusters
		m: number of attributes of SK
	"""
	def verify(self,**kwargs):
		cipher_clusters = kwargs.get("cipher_clusters") 
		Ss              = []
		for cipher_cluster in cipher_clusters:
			S  = self.liu_scheme.decryptMatrix(
				ciphertext_matrix = cipher_cluster,
				secret_key        = self.sk,
				m                 = self.m
			)
			Ss.append(S)
		return Ss
